class Solution {
    public int findMinimumOperations(String s1, String s2, String s3) {
        int minOperations = INT_MAX;
        int s1Len = s1.length();
        int s2Len = s2.length();
        int s3Len = s3.length();

        if (s1Len == s2Len && s1Len == s3Len) {
            return s1Len;
        }

        if (s1Len < s2Len) {
            for (int i = s1Len - 1; i >= 0; i--) {
                if (s1.charAt(i) != s2.charAt(i) && s1.charAt(i) != s3.charAt(i)) {
                    minOperations = Math.min(minOperations, i + 1);
                }
            }
        } else {
            for (int i = 0; i < s1Len; i++) {
                if (s1.charAt(i) != s2.charAt(i) && s1.charAt(i) != s3.charAt(i)) {
                    minOperations = Math.min(minOperations, i + 1);
                }
            }
        }
        return minOperations;
    }
}
